def write_csv(rows, filename):
    with open(OUT / filename, "w", newline="", encoding="utf-8") as f:
        w = csv.writer(f)
        w.writerow(HEADER)
        w.writerows(rows)
    print(f"Written: {filename} ({len(rows)} rows)")


